class Solution {
public:
    int clumsy(int n) {
        if (n % 4 == 1) return n;
        if (n % 4 == 2) return n * (n - 1) / (n - 2) + 1;
        if (n % 4 == 3) return n * (n - 1) / (n - 2) - (n - 3);
        return n * (n - 1) / (n - 2) + (n - 3) / (n - 4);
    }
};
